import sys
from itertools import product

def solve():
    s = sys.stdin.readline().strip()
    n = len(s)
    if s == '0':
        print(1)
        return
    if n < 2:
        print(0)
        return

    x_positions = [i for i, ch in enumerate(s) if ch == 'X']
    underscore_positions = [i for i, ch in enumerate(s) if ch == '_']
    x_value = None
    count = 0

    # Determine possible X values (0-9)
    x_options = range(10)
    if x_positions:
        # Leading X can't be 0
        if 0 in x_positions:
            x_options = range(1, 10)

    for x_val in x_options:
        temp = list(s)
        for pos in x_positions:
            temp[pos] = str(x_val)
        # Now handle underscores
        underscore_count = temp.count('_')
        if underscore_count == 0:
            num = int(''.join(temp))
            if num % 25 == 0 and temp[0] != '0':
                count += 1
        else:
            # Generate all possible combinations for underscores
            leading_zero = False
            if temp[0] == '_':
                # First digit can't be 0
                underscore_options = [range(1, 10)] + [range(10)] * (underscore_count - 1)
            else:
                underscore_options = [range(10)] * underscore_count

            for values in product(*underscore_options):
                temp2 = temp.copy()
                value_iter = iter(values)
                for i in range(n):
                    if temp2[i] == '_':
                        temp2[i] = str(next(value_iter))
                if temp2[0] == '0':
                    continue
                num = int(''.join(temp2))
                if num % 25 == 0:
                    count += 1
    print(count)

